from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["first-pc-install-ready-pack-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>First PC Install Ready Pack</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0;--ok:#22c55e;--warn:#f59e0b}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#173766,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px}button{font:inherit;border-radius:16px;border:0;background:linear-gradient(135deg,#0284c7,#38bdf8);color:#02101b;font-weight:1000;padding:12px}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}.step{border-left:3px solid var(--ok);padding:8px 10px;background:#081226;border-radius:14px}.warn{border-left-color:var(--warn)}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>First PC Install Ready Pack</h1><p class="muted">Pack rápido para instalar e arrancar GodModeDesktop.exe no PC, sem segredos no repo e com autoevolução sempre gated.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="location.href='/app/first-pc-runtime-verification'" class="dark">Runtime Check</button><button onclick="pkg()">Pack completo</button><button onclick="checklist()">Checklist</button><button onclick="contract()">Contrato start</button></div></section><section class="panel"><h2>Arranque local</h2><div id="steps" class="grid"></div></section><section class="panel"><h2>Rotas essenciais PC</h2><div class="grid" id="routes"></div></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function esc(s){return String(s).replaceAll('<','&lt;')}function show(x){qs('#out').textContent=JSON.stringify(x,null,2);render(x)}function render(x){const p=x?.ready_pack||x;const steps=p?.one_click_local_start_contract?.first_start_steps||p?.first_start_steps||[];qs('#steps').innerHTML=steps.map((s,i)=>`<div class="step"><b>${i+1}</b> ${esc(s)}</div>`).join('');const routes=p?.essential_local_routes||[];qs('#routes').innerHTML=routes.map(r=>`<button class="dark" onclick="location.href='${esc(r.route)}'">${esc(r.label)}</button>`).join('')}async function pkg(){show(await api('/api/first-pc-install-ready-pack/package'))}async function checklist(){show(await api('/api/first-pc-install-ready-pack/checklist'))}async function contract(){show(await api('/api/first-pc-install-ready-pack/one-click-local-start-contract'))}pkg()</script></body></html>
"""


@router.get('/app/first-pc-install-ready-pack', response_class=HTMLResponse)
async def first_pc_install_ready_pack_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/pc-install-ready', response_class=HTMLResponse)
async def pc_install_ready_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
